// Solution
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<int> bubbleSort(vector<int>& nums) {
        for (int i = 0; i < nums.size(); i++) {
            bool swapped = false;
            for (int j = 0; j < nums.size() - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                    swapped = true;
                }
            }
            if (!swapped) {
                break;
            }
        }
        return nums;
    }
};

int main() {
    Solution solution;
    vector<int> nums = {5, 2, 8, 3, 1, 6, 4};
    vector<int> sortedNums = solution.bubbleSort(nums);
    for (int num : sortedNums) {
        cout << num << ' ';
    }
    return 0;
}

